// CheckAvailability checks product availability using distributed cachingfunc (i *InventoryManager) CheckAvailability(ctx context.Context, productID int, requestedQuantity int) (*ProductAvailability, error) {    cacheKey := fmt.Sprintf("product:%d", productID)        // Try cache first    cached, err := i.getFromCache(ctx, cacheKey)    if err == nil {        return cached, nil    }    // Cache miss or expired, get from database    return i.getFromDatabase(ctx, productID, requestedQuantity)}func (i *InventoryManager) getFromCache(ctx context.Context, cacheKey string) (*ProductAvailability, error) {    var availability ProductAvailability    data, err := i.redis.Get(ctx, cacheKey).Result()    if err != nil {        return nil, err    }    err = json.Unmarshal([]byte(data), &availability)    if err != nil {        return nil, fmt.Errorf("failed to unmarshal cache data: %w", err)    }    return &availability, nil}func (i *InventoryManager) getFromDatabase(ctx context.Context, productID int, requestedQuantity int) (*ProductAvailability, error) {    tx, err := i.db.BeginTx(ctx, &sql.TxOptions{        Isolation: sql.LevelSerializable,    })    if err != nil {        return nil, fmt.Errorf("failed to begin transaction: %w", err)    }    defer func() {        if err != nil {            if rbErr := tx.Rollback(); rbErr != nil {                fmt.Printf("Failed to rollback transaction: %v
", rbErr)            }        } else {            if err = tx.Commit(); err != nil {                fmt.Printf("Failed to commit transaction: %v
", err)            }        }    }()    var product Product    row := tx.QueryRowContext(ctx, `        SELECT product_id, quantity, status, version         FROM products         WHERE product_id = ?         FOR SHARE`, productID)    err = row.Scan(&product.ProductID, &product.Quantity, &product.Status, &product.Version)    if err != nil {        if errors.Is(err, sql.ErrNoRows) {            return nil, fmt.Errorf("product %d not found", productID)        }        return nil, fmt.Errorf("failed to select product: %w", err)    }    availability := &ProductAvailability{        ProductID: product.ProductID,        Available: product.Quantity >= requestedQuantity,        Quantity:  product.Quantity,        Status:    product.Status,        Version:   product.Version,    }    // Cache the result    cacheKey := fmt.Sprintf("product:%d", productID)    i.mutex.Lock()    i.cacheKeys[cacheKey] = true    i.mutex.Unlock()    err = i.redis.Set(ctx, cacheKey, availability, i.cacheTTL).Err()    if err != nil {        fmt.Printf("Failed to cache result: %v
", err)    }    return availability, nil}
